create table dirkspzm32.s_qs_babtec_wa_lief (
    auftragnummer     varchar2(30 char) not null enable,
    artikel           varchar2(30 char) not null enable,
    lieferscheinnr    varchar2(30 char),
    lieferscheinpos   varchar2(30 char),
    lieferdatum       date,
    liefermengesoll   number(*, 3),
    liefermengeist    number(*, 3),
    sollterminliefern date,
    istterminliefern  date,
    kundennr          varchar2(30 char),
    bestellnr         varchar2(30 char),
    bestelldatum      date,
    status            varchar2(3 char),
    erstell_datum     date default sysdate,
    bearb_datum       date,
    fehler_code       number(*, 5),
    fehler_text       varchar2(255 char)
);

alter table dirkspzm32.s_qs_babtec_wa_lief
    add constraint pk_s_qs__babtec_wa_lief primary key ( auftragnummer,
                                                         artikel )
        using index enable;


